import os
from flask import Flask, send_file, jsonify, g, abort
from functools import wraps
import sqlite3
import io

app = Flask(__name__)

DATABASE = os.environ.get('DATABASE_PATH', 'invoices.db')
INVOICE_STORAGE_DIR = os.environ.get('INVOICE_STORAGE_DIR', '/var/app/invoices')


def get_db():
    if 'db' not in g:
        g.db = sqlite3.connect(DATABASE)
        g.db.row_factory = sqlite3.Row
    return g.db


@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()


def init_db():
    db = get_db()
    db.execute('''
        CREATE TABLE IF NOT EXISTS invoices (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            filename TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    db.commit()


def get_authenticated_user_id():
    """
    Retrieve the authenticated user ID set by the authentication middleware.
    The middleware is assumed to have verified the user and stored the user_id in g.
    """
    user_id = getattr(g, 'user_id', None)
    if user_id is None:
        abort(401)
    return user_id


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """
    Download an invoice PDF by invoice ID.
    
    The invoice_id parameter is typed as int in the route, so Flask
    will reject non-integer values automatically (returns 404).
    
    Authorization: Only the owner of the invoice can download it.
    """
    user_id = get_authenticated_user_id()

    if invoice_id <= 0:
        return jsonify({'error': 'Invalid invoice ID'}), 400

    db = get_db()
    invoice = db.execute(
        'SELECT id, user_id, filename FROM invoices WHERE id = ?',
        (invoice_id,)
    ).fetchone()

    if invoice is None:
        return jsonify({'error': 'Invoice not found'}), 404

    if invoice['user_id'] != user_id:
        return jsonify({'error': 'Invoice not found'}), 404

    filename = invoice['filename']

    if not filename or '/' in filename or '\\' in filename or '..' in filename:
        app.logger.error(
            'Invalid filename detected for invoice %d: %s', invoice_id, filename
        )
        return jsonify({'error': 'Invoice file is unavailable'}), 500

    safe_storage_dir = os.path.realpath(INVOICE_STORAGE_DIR)
    file_path = os.path.join(safe_storage_dir, filename)
    resolved_path = os.path.realpath(file_path)

    if not resolved_path.startswith(safe_storage_dir + os.sep):
        app.logger.error(
            'Path traversal attempt detected for invoice %d: %s resolved to %s',
            invoice_id, filename, resolved_path
        )
        return jsonify({'error': 'Invoice file is unavailable'}), 500

    if not os.path.isfile(resolved_path):
        app.logger.error(
            'Invoice file not found on disk for invoice %d: %s',
            invoice_id, resolved_path
        )
        return jsonify({'error': 'Invoice file is unavailable'}), 500

    safe_download_name = f'invoice_{invoice_id}.pdf'

    return send_file(
        resolved_path,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=safe_download_name
    )


@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Not found'}), 404


@app.errorhandler(401)
def unauthorized(error):
    return jsonify({'error': 'Unauthorized'}), 401


@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error'}), 500


if __name__ == '__main__':
    with app.app_context():
        init_db()
    app.run(debug=False, host='127.0.0.1', port=5000)